var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇군…….","JPN":"そうか……","ENG":"I see...","TWN":"原來如此……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"역시 정말로 자네였나, 스완.","JPN":"やはり君だったのか、スワン。","ENG":"So it really was you, Swan.","TWN":"果然真的是你，史旺。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 이방인들의 말이 사실이었어. 정말로 이렇게 스완이 나타날 줄이야.","JPN":"異邦人たちの話は本当だった。本当にこうやってスワンが現れるとは。","ENG":"What those outsiders said was true. I never imagined you'd show up like this.","TWN":"那些外邦人說的是真的。沒想到史旺真的會出現。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그것도 이렇게나 성장한 모습으로 말이지. 이거 예상했던 것보다 훨씬 감회가 새롭군.","JPN":"それもこんなに成長した姿で。予想していたよりもずっと感慨深いものだな。","ENG":"And looking so grown-up, too. This hits a lot harder than I expected.","TWN":"而且看起來這麼成熟，這感覺比我預想的還要強烈。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래서? 그동안 어떻게 지냈나?","JPN":"それで？　元気だったかね？","ENG":"So? How have you been all this time?","TWN":"那麼？這段時間你過得怎麼樣？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"딱히…….","JPN":"別に……","ENG":"Well...","TWN":"嗯……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"잘 지냈다고 말은 못하겠군요.","JPN":"元気だったとは言えませんね。","ENG":"I can't say I've been doing very well.","TWN":"說不上過得很好。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"잠깐, 그 우산은 틀림없이 내 마도구로군.","JPN":"おお、その傘は私の魔道具だな。","ENG":"Wait, that umbrella is my Curio, isn't it?","TWN":"等等，那把傘是我的魔法道具，對吧？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"알고 있나? 그건 어떤 충격이라도 한 번은 사용자를 지켜주는 마도구야.","JPN":"知っているかい？　それはどんな衝撃からも一度は使用者を守ってくれる魔道具なのだ。","ENG":"Do you know? It's a Curio that protects the user from any single shock.","TWN":"你知道嗎？那是一個能保護使用者免受任何一次衝擊的魔法道具。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그걸 가지고 있다는 뜻은… 설마 그 우산이 자네 목숨을 지켜준 적이 있다는 뜻인가……?","JPN":"それを持っているということは……傘が君の命を守ったことがあったということだろうか……？","ENG":"If you've got it, then... does it mean that it saved your life once...?","TWN":"如果你還留著它……是不是表示它曾經救過你一命……？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 그렇다면 정말로 기쁠 텐데 말이지.","JPN":"ふふ、それなら本当に嬉しいが。","ENG":"Haha, if that's true, then I'm really glad.","TWN":"哈哈，如果是真的，那我真的很高興。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……아니요.","JPN":"……いいえ。","ENG":"...No.","TWN":"……沒有。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 물려받았던 시점에서 이건 이미 용도를 다한 평범한 우산이었답니다.","JPN":"私が譲り受けた時点で、すでにその役を終えた普通の傘でした。","ENG":"By the time I inherited it, it was already just an ordinary umbrella.","TWN":"等我繼承它的時候，它已經只是一把普通的傘了。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래? 그거 아쉽게 됐군.","JPN":"そうなのか？　それは残念だ。","ENG":"Really? That's a shame.","TWN":"真的嗎？那真可惜。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그래도 지금까지 소중하게 간직해 주어서 무척 기쁘다네.","JPN":"だが、それでも今まで大事にしてくれてとても嬉しい。","ENG":"Still, I'm truly grateful you've treasured it until now.","TWN":"不過，我真的很感激你一直珍惜著它。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 그건 그렇고 어느새 키가 훌쩍 자라버렸군.","JPN":"ふふ、それはそうとして、いつの間にか背が伸びたんたな。","ENG":"Haha, and look at you now. You've grown so tall.","TWN":"哈哈，看看你現在，長得真高了。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이제는 정말로 훌륭한 레이디라고 불러도 손색이 없겠어.","JPN":"もう立派なレディーと呼んでもいいくらいだ。","ENG":"You've become a proper lady, without a doubt.","TWN":"你絕對是一位真正的淑女了。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러는 당신은 여전히 제 기억 속 그 모습 그대로군요.","JPN":"そういうあなたは、相変わらず私の記憶の中のままですね。","ENG":"And yet you look exactly the same as you do in my memory.","TWN":"但你看起來和我記憶中的一模一樣。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"뭐, 그야 그렇겠지.","JPN":"まあ、それはそうだろう。","ENG":"Well, that makes sense.","TWN":"嗯，那也說得通。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"애초에 이 세계는 자네의 <color=#ffd34c>기억</color>으로부터 재창조된 허상에 불과하지 않은가?","JPN":"そもそもこの世界は君の<color=#ffd34c>記憶</color>から再創造された虚像に過ぎない。","ENG":"This world is nothing but an illusion recreated from your <color=#ffd34c>memories</color>, isn't it?","TWN":"這個世界不過是從你的<color=#ffd34c>記憶</color>中重現的幻象，不是嗎？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"줄곧 이상하다고 생각했다네, 스완.","JPN":"ずっとおかしいとは思っていた、スワン。","ENG":"It's always bothered me, Swan.","TWN":"我一直覺得很奇怪，史旺。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 이방인들의 말이 사실이라면…….","JPN":"異邦人たちの話が本当なら……","ENG":"If what those outsiders said is true...","TWN":"如果那些外邦人說的是真的……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 자네가 정말로 모든 걸 돌이킬 수 있는 힘을 얻게 되었다면…….","JPN":"そして君が本当に全てを元に戻せる力を手に入れたのなら……","ENG":"And if you really did gain the power to undo everything...","TWN":"如果你真的獲得了能夠扭轉一切的力量……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"어째서 심야의 살인마 사건이 발생한 시점으로 세계를 되돌릴 수밖에 없었는지 말이야.","JPN":"なぜ深夜の殺人鬼事件が発生した時点にしか世界を戻さないのか。","ENG":"Why did you choose to rewind the world to the time of the Midnight Killer case?","TWN":"為什麼世界只能回到午夜殺人魔事件發生的時間點呢。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"간단한 이야기라네, 스완.","JPN":"簡単な話だ、スワン。","ENG":"It's simple, my dear Swan.","TWN":"這很簡單，史旺。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"애초부터 자네는 이럴 수밖에 없었던 거야.","JPN":"初めから君はこうするしかなかったのだ。","ENG":"You never had a choice.","TWN":"從一開始你就只能這樣。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};